import Link from "next/link";
import { prisma } from "@/src/lib/prisma";

async function deleteSelectedJobs(formData: FormData) {
  "use server";

  const jobIds = formData
    .getAll("jobIds")
    .map((v) => String(v))
    .filter(Boolean);

  if (jobIds.length === 0) return;

  const ads = await prisma.ad.findMany({
    where: { jobId: { in: jobIds } },
    select: { id: true },
  });

  const adIds = ads.map((a) => a.id);

  // Delete children first to avoid FK constraint issues.
  if (adIds.length > 0) {
    await prisma.image.deleteMany({
      where: { adId: { in: adIds } },
    });
  }

  await prisma.referenceAsset.deleteMany({
    where: { jobId: { in: jobIds } },
  });

  await prisma.ad.deleteMany({
    where: { jobId: { in: jobIds } },
  });

  await prisma.job.deleteMany({
    where: { id: { in: jobIds } },
  });

  // Keep the UI simple after delete.
  // eslint-disable-next-line no-restricted-globals
  (globalThis as any).location?.assign?.("/");
}

export default async function HomePage() {
  const jobs = await prisma.job.findMany({
    orderBy: {
      createdAt: "desc",
    },
  });

  return (
    <main
      style={{
        padding: 40,
        maxWidth: 1000,
        margin: "0 auto",
        background: "linear-gradient(180deg, #f7f8fc 0%, #ffffff 70%)",
        color: "#0f172a",
        minHeight: "100vh",
      }}
    >
      <h1>My AI CRM</h1>
      <p style={{ marginTop: 8 }}>Submit websites and track jobs.</p>

      <div style={{ marginTop: 18 }}>
        <Link
          href="/new"
          style={{
            display: "inline-block",
            padding: "10px 14px",
            borderRadius: 10,
            border: "1px solid #111827",
            background: "#111827",
            color: "white",
            textDecoration: "none",
          }}
        >
          Create New Job
        </Link>
      </div>

      <div style={{ marginTop: 28 }}>
        <details>
          <summary
            style={{
              cursor: "pointer",
              fontWeight: 800,
              color: "#0f172a",
            }}
          >
            Previous URLs
          </summary>

          <div style={{ marginTop: 12 }}>
            {jobs.length === 0 ? (
              <p style={{ opacity: 0.8 }}>No previous URLs yet.</p>
            ) : (
              <form action={deleteSelectedJobs}>
                <div style={{ fontSize: 13, opacity: 0.8, marginBottom: 10 }}>
                  Select one or more campaigns to delete.
                </div>

                <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
                  {jobs.map((job) => (
                    <li
                      key={job.id}
                      style={{
                        marginBottom: 10,
                        border: "1px solid #e5e7eb",
                        borderRadius: 12,
                        padding: 12,
                        background: "white",
                      }}
                    >
                      <label
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: 10,
                        }}
                      >
                        <input
                          type="checkbox"
                          name="jobIds"
                          value={job.id}
                        />
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ fontSize: 13, wordBreak: "break-word" }}>
                            {job.url}
                          </div>
                          <div style={{ fontSize: 12, opacity: 0.7 }}>
                            {job.status}
                          </div>
                        </div>
                        <Link
                          href={`/jobs/${job.id}`}
                          style={{
                            fontSize: 12,
                            color: "#111827",
                            textDecoration: "none",
                            opacity: 0.75,
                            whiteSpace: "nowrap",
                          }}
                        >
                          Open
                        </Link>
                      </label>
                    </li>
                  ))}
                </ul>

                <div style={{ marginTop: 12 }}>
                  <button
                    type="submit"
                    style={{
                      padding: "10px 14px",
                      borderRadius: 10,
                      border: "1px solid #111827",
                      background: "#111827",
                      color: "white",
                      cursor: "pointer",
                    }}
                  >
                    Delete Selected
                  </button>
                </div>
              </form>
            )}
          </div>
        </details>
      </div>
    </main>
  );
}
